# INSIGHT: Trie guides DFS — prune branches not matching any word prefix
root = build_trie(words)  # insert all words
result = set()
def dfs(r, c, node, path):
    if not (0<=r<rows and 0<=c<cols) or board[r][c] not in node.children:
        return
    char = board[r][c]
    node = node.children[char]
    path += char
    board[r][c] = '#'  # mark visited
    if node.is_end: result.add(path)
    for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]:
        dfs(r+dr, c+dc, node, path)
    board[r][c] = char  # restore
    # Optimization: prune leaf trie nodes after finding word
for r in range(rows):
    for c in range(cols): dfs(r, c, root, '')
